mapper.select:
SELECT u.name AS studentName, l.start_time AS startTime, l.end_time AS endTime, l.day_of_week AS dayOfWeek, s.name AS subjectName FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN user u ON se.student_id = u.user_id INNER JOIN lecture l ON se.lecture_id = l.lecture_id INNER JOIN subject s ON s.subject_id = l.subject_id WHERE se.lecture_id IN ( SELECT lecture_id FROM teacher_assignment WHERE teacher_id = #{teacherId} )
AND (u.name LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY u.name LIMIT #{startRow}, #{rowPerPage}

mapper.update:
UPDATE user
SET phone = #{phone},
    address = #{address},
    password = #{password}
WHERE user_id = #{teacherId}

mapper.select:
SELECT u.name AS studentName, l.start_time AS startTime, l.end_time AS endTime, l.day_of_week AS dayOfWeek, s.name AS subjectName, a.attend_date AS attendDate, a.status FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN user u ON se.student_id = u.user_id INNER JOIN lecture l ON se.lecture_id = l.lecture_id INNER JOIN subject s ON s.subject_id = l.subject_id INNER JOIN attendance a ON p.payment_id = a.payment_id WHERE se.lecture_id IN ( SELECT lecture_id FROM teacher_assignment WHERE teacher_id = #{teacherId} )
AND ( u.name LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%') OR a.status LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY a.attend_date DESC LIMIT #{startRow}, #{rowPerPage}

SELECT album_id, lecture_id, title, description, created_at FROM album
WHERE title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY created_at DESC LIMIT #{startRow}, #{rowPerPage}
